def one_hot(categories):
    unique = sorted(set(categories))
    result = {}
    for cat in unique:
        result[cat] = [1 if val == cat else 0 for val in categories]
    return result

data = ['apple', 'banana', 'cherry', 'apple', 'cherry', 'banana']
encoded = one_hot(data)
print("Data:", data)
print("\nEncoded:")
for key in sorted(encoded.keys()):
    print(f"  {key}: {encoded[key]}")
